var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그 아이는 나의 모든 것이다","JPN":"あの子は私のすべてだ。","ENG":"She is everything to me.","TWN":"那個孩子是我的全部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"나 또한 그 아이의 모든 것이다.","JPN":"私もまた、あの子のすべてだ。","ENG":"And I am everything to her.","TWN":"而我，也是那個孩子的全部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그러기에 우리는 약속한다.","JPN":"だから私たちは約束を交わす。","ENG":"So we make this promise.","TWN":"為此，我們許下承諾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"차가운 셀룰로이드 심장이 품은 꿈결은 태엽을 쥔 나의 손길로… 그 어떤 행복한 동화보다 오래도록 맥동할 것임을.","JPN":"冷たいセルロイドの心臓が抱く夢は、ぜんまいを握る私の手によって……どんなおとぎ話よりも長く長く脈を打つと。","ENG":"The dream that beats within her cold celluloid heart will keep pulsing in my hands... longer than any happy fairy tale ever could.","TWN":"冰冷的賽璐珞之心所懷抱的夢境，將會透過我手中緊握的發條，比任何幸福的童話更加長久地脈動下去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"히히, 오늘도 좋은 이야기였어. 들려줘서 고마워.","JPN":"えへへ、今日も素敵なお話だったよ。聞かせてくれてありがとう。","ENG":"Hehe, that was another wonderful story. Thanks for telling it to me.","TWN":"嘿嘿，今天也是個很棒的故事呢。謝謝你說給我聽。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"아빠는 대단해. 어떻게 이런 재밌는 이야기를 많이 알고 있는 걸까?","JPN":"パパは本当にすごい。どうしてこんなに面白いお話をたくさん知ってるの？","ENG":"Daddy, you're amazing. How do you know so many fun stories?","TWN":"爸爸你好厲害。怎麼會知道這麼多有趣的故事呀？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"시간 날 때마다 더 자주 듣고 싶어.","JPN":"時間ができたらもっともっと聞かせて欲しいな。","ENG":"I want to hear them more often whenever you have time.","TWN":"一有空我就想多聽你講一些。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"그치만 이야길 들을수록 무섭기도 해.","JPN":"……でも、正直に言うとね。怖い、って気持ちもあるんだ。","ENG":"But the more I listen, the scarier it feels.","TWN":"可是，故事聽得越多，我就越感到害怕。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"언젠가 아빠가 나한테 해주고 싶은 이야기가 다 떨어져버릴까 봐.","JPN":"話し尽くして、いつか私に聞かせる話がなくなっちゃうんじゃないかって。","ENG":"What if someday you run out of stories to tell me?","TWN":"因為我怕，總有一天爸爸會沒有故事可以再講給我聽了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"나한테 해줄 더 많은 이야길 찾기 위해 내 곁을 떠났다가 영영 돌아오지 않을까 봐.","JPN":"私に聞かせるためのお話を探しに出かけて、永遠に帰って来なくなったらどうしようって。","ENG":"What if you go away to find more stories for me and never come back?","TWN":"你會為了找更多故事給我聽，而離開我身邊，然後就永遠不回來了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"가끔은 그런 생각에 너무 사로잡혀서, 아빠가 영원히 날 떠나지 못하게 하고 싶었어.","JPN":"時々そんな心配が止まらなくなって、パパをずっと私のそばに引き止めておきたくなる。","ENG":"Sometimes, I get so scared of that thought that I almost want to keep you from ever leaving me again.","TWN":"有時候，我會被那種想法深深困住，很想讓爸爸永遠都不能離開我。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"그치만 말이야.","JPN":"でもね。","ENG":"But you know what?","TWN":"不過話說回來。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"내가 바깥 세상 이야기를 동경하고 좋아하는 만큼, 그곳을 자유롭게 누릴 수 있는 멋진 아빠가 좋아.","JPN":"私が外の世界の話に憧れたり、好きになったりするくらい、そこを自由に駆け回る素敵なパパが好きなの。","ENG":"As much as I love hearing about the outside world, I love that you can live freely in it even more.","TWN":"比起我對外面世界故事的憧憬和喜愛，我更愛能在其中自由闖蕩的帥氣爸爸。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"이 방에 갇혀 살아야 하는 건 나 혼자로도 충분하니까.","JPN":"この部屋にずっと閉じ込められるのは、私一人で十分だから。","ENG":"I'm the only one who needs to stay here, locked in this room.","TWN":"因為被困在這個房間裡的人，有我一個就夠了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"에이, 아빠가 왜 나한테 미안해.","JPN":"そんな、パパが謝ることないよ。","ENG":"Oh, you don't have to be sorry, Daddy.","TWN":"哎呀，爸爸你幹嘛要跟我說對不起嘛。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"따스한 온기를 흘려보내는 혈관도, 태엽과 인형실 없이 움직이는 자유로운 몸도 갖고 싶지만…","JPN":"暖かい温もりが流れる血管も、ぜんまいと糸がなくても動ける自由な体も欲しいけど……","ENG":"Sure, I wish I had warm blood flowing through my veins and a body that moves without strings or springs...","TWN":"當然，我也想要擁有流淌著溫暖血液的血管，和沒有發條及絲線也能自由活動的身體……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"날 만들어주고 요정님을 만나 소원까지 이룬 최고의 아빠가 지금 내 곁에 있는 걸?","JPN":"私を作ってくれて、しかも妖精さんに願いを叶えてもらった最高のパパがそばにいるんだから。","ENG":"But the best Daddy in the world is right here with me. The one who made me, met the Fairy Godmother, and got his wish to come true.","TWN":"因為，替我打造身體、遇見了仙女、還實現了願望的這位世界上最棒的爸爸，就在我身邊呀！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"이렇게 집에서 아빠를 기다릴 수 있다는 것만으로도 난 정말 행복해.","JPN":"こうして家でパパを待っていられるだけで、私はすごく幸せだよ。","ENG":"Just being able to wait for you at home like this makes me truly happy.","TWN":"能夠像這樣在家裡等著爸爸，我就已經感到非常幸福了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"그러니까 다음에 돌아올 땐 더 멋진 이야기와 함께, 오늘 말한 이국의 예쁜 드레스를 구해서 돌아와줘.","JPN":"だから次はもっと素敵なお話と、今日教えてくれた異国のきれいなドレスをお土産に持ってきてね。","ENG":"So next time you come back, bring an even better story and that pretty dress you mentioned today.","TWN":"所以下次回來的時候，請帶給我更精彩的故事，和今天說的那件異國的美麗洋裝作禮物吧！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"나쁜 늑대나 거짓말쟁이 여우를 만나면 꼭 조심하구!","JPN":"悪い狼とか嘘つきの狐に出会ったら気をつけるんだよ！","ENG":"And please, be careful of the mean Wolf and the lying fox on your way, okay?","TWN":"遇到壞心眼的狼和說謊的狐狸時，一定要多加小心喔！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"난 이제 피곤해. 좋은 꿈 꾸라고 말해줘.","JPN":"もう疲れちゃった。おやすみって言ってくれる？","ENG":"I'm sleepy now. Tell me to have sweet dreams.","TWN":"我累了，現在想睡覺。請跟我說聲「晚安，做個好夢」吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_NULL_SPECIAL","text":{"KOREA":"아빠가 다시 내 태엽을 돌려줄 때까지, 얌전히 기다릴 테니까.","JPN":"パパがまたぜんまいを巻いてくれるまで、大人しく待ってるから。","ENG":"I'll wait patiently until you wind my spring again.","TWN":"我會乖乖地等到爸爸再次為我上發條為止。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_SPECIAL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};